API_name: nchu_course_teachers_search_by_name
Description:
{
  "description": "從課程資料依姓名搜尋中興大學教師。",
  "required_parameters": [
    {
      "name": "name",
      "type": "STRING",
      "description": "欲搜尋的教師姓名(例如：范耀中、吳俊霖、陳煥)"
    }
  ],
  "optional_parameters": [
    {
      "name": "exact_match",
      "type": "BOOLEAN",
      "description": "是否使用完全比對（預設為否）",
      "default": false
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 30）",
      "default": 30
    }
  ]
}

